/**
 *  Outcome of a tool call. `Err` carries a short, user-friendly message —
 *  never the full `AppError` chain — because the summary is rendered in the
 *  Settings activity feed.
 */
export type ActivityResult =
/**  The tool call completed successfully. */
{ kind: "ok" } |
/**
 *  The tool call failed. `String` is a short error description (e.g.
 *  `"block not found"`), not a serialized `AppError`.
 */
{ kind: "err"; message: string };

/**
 *  Discriminates the caller kind on an activity entry without carrying any
 *  identifying name in Debug output. Agent identifiers (when present) live
 *  on [`ActivityEntry::agent_name`] and are redacted from the `Debug` impl.
 */
export type ActorKind =
/**
 *  Tool call originated from a user action in the UI (today this never
 *  Happens for the RO server; reserved for RW tools).
 */
"user" |
/**
 *  Tool call originated from an external agent connected via the MCP
 *  socket.
 */
"agent";

/**
 *  A composable advanced query: a boolean [`FilterExpr`] tree over the
 *  structural filter dimensions, scoped to one space, with an optional
 *  multi-key sort and keyset cursor.
 *
 *  The `filter` defaults to `And { children: [] }` — the TRUE expression
 *  (`1=1`), i.e. "every block in the space". `sort` defaults to empty (the
 *  engine applies its default keyset on `b.id DESC`). `limit` defaults to
 *  the engine's [`engine::DEFAULT_LIMIT`].
 */
export type AdvancedQueryRequest = {
	/**
	 *  The space the query is scoped to. Always applied as
	 *  `b.space_id = ?` regardless of any `Space` leaf in `filter`.
	 */
	spaceId: string,
	/**
	 *  The boolean filter tree. Defaults to the TRUE expression
	 *  (`And { children: [] }`) so an omitted filter returns every block in
	 *  the space.
	 */
	filter?: FilterExpr,
	/**
	 *  Ordered sort keys. Each key terminates in the `b.id` tiebreaker so
	 *  the keyset is always stable. Empty → the engine's default keyset.
	 */
	sort?: SortKey[],
	/**
	 *  Opaque keyset cursor from a prior page's `next_cursor`. `None` =
	 *  first page.
	 */
	cursor?: string | null,
	/**
	 *  Page size. `None` → [`engine::DEFAULT_LIMIT`]; bounded by
	 *  [`engine::MAX_LIMIT`].
	 */
	limit?: number | null,
	/**
	 *  Optional full-text term. When `Some(q)`, the query composes an FTS5
	 *  `MATCH` over `fts_blocks` (sanitised via the shared FTS sanitiser)
	 *  INTERSECTED with the structural `filter`, exposes the per-row `bm25`
	 *  relevance via [`QueryResultRow::score`], and defaults the sort to
	 *  [`SortSource::Relevance`] (best-first) when no explicit `sort` is
	 *  given. When `None`, the query is purely structural (full backward
	 *  compat with the C1 engine) and [`SortSource::Relevance`] is rejected.
	 */
	fulltext?: string | null,
	/**
	 *  Optional grouping. When `Some`, the engine runs the GROUPED path:
	 *  it buckets the matched rows by the [`GroupSpec`]'s dimension and
	 *  returns [`AdvancedQueryResponse::groups`] (per-bucket count + a
	 *  bounded member preview) with group-level keyset pagination, leaving
	 *  [`AdvancedQueryResponse::rows`] empty. When `None` (the default), the
	 *  engine runs the FLAT path exactly as before (full backward compat).
	 */
	groupBy?: GroupSpec | null,
	/**
	 *  Optional aggregates (`count` / `sum` / `avg` / `min` / `max`). Computed
	 *  GLOBALLY over the full match set into [`AdvancedQueryResponse::aggregates`]
	 *  and, when `group_by` is set, PER-GROUP into each [`QueryGroup::aggregates`]
	 *  (same order as this list). Non-numeric property/column values are SKIPPED
	 *  by the numeric-skip guard (see [`engine`]), so e.g. `avg` divides by the
	 *  numeric count, not the row count. Empty (the default) → no aggregates and
	 *  the response's `aggregates` slots stay empty (full backward compat).
	 */
	aggregates?: AggregateSpec[],
};

/**
 *  The paginated result of an advanced query.
 *
 *  In FLAT mode (`group_by` absent) `rows` carries the page and `groups` is
 *  empty. In GROUPED mode (`group_by` present) `groups` carries the bucket
 *  page and `rows` is empty. `next_cursor` / `has_more` / `total_count`
 *  describe whichever axis is paged (rows in flat mode, groups in grouped
 *  mode — `total_count` is the total GROUP count in grouped mode).
 */
export type AdvancedQueryResponse = {
	/**  The page of matched rows (FLAT mode). Empty in grouped mode. */
	rows: QueryResultRow[],
	/**  The page of group buckets (GROUPED mode). Empty in flat mode. */
	groups?: QueryGroup[],
	/**
	 *  Opaque cursor for the next page, or `None` at the end. In grouped
	 *  mode this is the GROUP-level keyset cursor.
	 */
	nextCursor: string | null,
	/**  `true` when a further page exists. */
	hasMore: boolean,
	/**
	 *  Total matching rows ignoring the cursor/limit, computed on the FIRST
	 *  page only; `None` on cursor pages. In grouped mode this is the total
	 *  number of GROUPS over the same predicate.
	 */
	totalCount: number | null,
	/**
	 *  GLOBAL aggregate results (over the full match set, ignoring the
	 *  cursor/limit), in the SAME order as the request's `aggregates`. Like
	 *  `total_count`, computed on the FIRST page only (aggregates over the full
	 *  set are invariant across cursor pages) and empty on cursor pages. Also
	 *  empty when no aggregates were requested.
	 */
	aggregates?: AggregateResult[],
};

/**
 *  Bundled agenda filter for the [`list_blocks`] Tauri command.
 *
 *  Exists purely to keep `list_blocks`'s argument count under the
 *  `tauri-specta` 10-arg limit after Phase 2 added `space_id`.
 *  The three sub-fields were previously top-level parameters and are
 *  still threaded into `list_blocks_inner` as individual parameters —
 *  the bundling is a transport-layer concern. `None` means "no agenda
 *  filter applies" (the common case), and each sub-field remains
 *  optional inside the struct so callers can still specify a single
 *  date without the range, etc.
 *
 *  Serde `rename_all = "camelCase"` matches the Tauri command-arg
 *  convention (camelCase keys on the IPC boundary), so the hand-written
 *  TS wrapper in `src/lib/tauri.ts` can pass `{ dateRange, source, date }`
 *  without an extra translation layer.
 */
export type AgendaQuery = {
	/**  Single-date agenda lookup (`YYYY-MM-DD`). */
	date: string | null,
	/**  Date-range agenda lookup (inclusive on both ends). */
	dateRange: DateRange | null,
	/**  Optional source filter (`due_date` / `scheduled_date`). */
	source: string | null,
};

/**  The closed set of aggregate operators. */
export type AggOp =
/**
 *  Row count (`COUNT(*)` with no target, else `COUNT(<numeric expr>)`).
 *  Result lands in [`AggregateResult::count`] (an `i64`).
 */
"count" |
/**  Numeric sum. Result lands in [`AggregateResult::value`] (an `f64`). */
"sum" |
/**
 *  Numeric average over the NUMERIC rows (the non-numeric rows are skipped,
 *  so the denominator is the numeric count, not the row count).
 */
"avg" |
/**  Numeric minimum. */
"min" |
/**  Numeric maximum. */
"max";

/**
 *  The closed set of block columns an aggregate may fold. Closed (rather than a
 *  free `String`) so an aggregate column can NEVER be a user-controlled string
 *  spliced into SQL.
 *
 *  Both columns are numeric-coerced through the same numeric-skip guard as a
 *  property: `priority` is a TEXT column (it stores `select` values like
 *  `"1"`/`"2"`/`"3"` — or non-numeric labels, which are skipped), and
 *  `position` is INTEGER.
 */
export type AggregateColumn =
/**  `b.priority` (TEXT; numeric-coerced, non-numeric labels skipped). */
"priority" |
/**  `b.position` (INTEGER). */
"position";

/**
 *  One aggregate's computed result, in request order.
 *
 *  [`AggOp::Count`] fills `count` (the integer row/numeric count); the fold
 *  operators ([`AggOp::Sum`] / `Avg` / `Min` / `Max`) fill `value` (the `f64`
 *  result), which is `None` when the set is empty or every contributing value
 *  was non-numeric (so SQLite's aggregate saw only NULLs).
 */
export type AggregateResult = {
	/**  The operator this result is for (echoes the request, same order). */
	op: AggOp,
	/**
	 *  The `f64` result of a fold operator (`Sum` / `Avg` / `Min` / `Max`);
	 *  `None` for `Count` and for a fold over an empty / all-non-numeric set.
	 */
	value: number | null,
	/**  The integer result of [`AggOp::Count`]; `None` for the fold operators. */
	count?: number | null,
};

/**
 *  One requested aggregate: an operator over an optional target.
 *
 *  `Count` with no `target` is `COUNT(*)` (every matched row); `Count` WITH a
 *  target counts the rows whose target value is numeric (non-NULL after the
 *  numeric-skip coercion). `Sum` / `Avg` / `Min` / `Max` REQUIRE a numeric
 *  target — without one the aggregate yields `None` (there is nothing to fold).
 */
export type AggregateSpec = {
	/**  The aggregate operator. */
	op: AggOp,
	/**
	 *  What to aggregate over. `None` is only meaningful for [`AggOp::Count`]
	 *  (→ `COUNT(*)`); the fold operators with no target yield `None`.
	 */
	target?: AggregateTarget | null,
};

/**
 *  What an [`AggregateSpec`] aggregates over. Internally-tagged on `"type"`.
 *
 *  `Column` is a closed set of numeric-ish block columns (never a
 *  user-supplied identifier). `Property` aggregates the per-block NUMERIC
 *  value of a typed property; its `key` is BOUND as a `?` parameter, never
 *  interpolated. So aggregation cannot inject SQL.
 */
export type AggregateTarget =
/**  Aggregate a fixed numeric-ish block column (closed [`AggregateColumn`]). */
{ type: "Column";
/**  Which column to aggregate. */
name: AggregateColumn } |
/**
 *  Aggregate the numeric value of a typed property (`block_properties`),
 *  keyed by `key`. Non-numeric values are SKIPPED by the numeric guard.
 */
{ type: "Property";
/**  The property key whose `value_text` is read + numeric-coerced. */
key: string };

/**
 *  Helper struct matching the `{ kind, message }` JSON shape that [`AppError`]
 *  serialises to.  Used solely so specta can derive the TypeScript type for
 *  `AppError` — the real serialisation is still handled by the manual
 *  `Serialize` impl below.
 */
export type AppError = {
	kind: string,
	message: string,
};

export type AttachmentRow = {
	id: BlockId,
	block_id: BlockId,
	mime_type: string,
	filename: string,
	size_bytes: number,
	fs_path: string,
	/**  Epoch-ms (attachments.created_at is INTEGER since migration 0081). */
	created_at: number,
	/**
	 *  blake3 hex digest of the file bytes (#1453 Phase 1). Same scheme as the
	 *  file-sync layer (`sync_files.rs`), so it matches the sync offer's hash.
	 *
	 *  `None` for rows attached before migration 0093, or whose file was
	 *  missing on disk when the boot-time backfill ran. Persisted only — the
	 *  dedup / skip-transfer / mutation-safety USES of it are follow-ups.
	 */
	content_hash?: string | null,
};

/**
 *  Tagged union of filter predicates for backlink queries.
 *
 *  Filters are combined with AND semantics at the top level.
 *  Use `And`/`Or`/`Not` variants for compound boolean logic.
 */
export type BacklinkFilter = { type: "PropertyText"; key: string; op: CompareOp; value: string } | { type: "PropertyNum"; key: string; op: CompareOp; value: number | null } | { type: "PropertyDate"; key: string; op: CompareOp; value: string } | { type: "PropertyIsSet"; key: string } | { type: "PropertyIsEmpty"; key: string } |
/**  Filter blocks by todo_state column (direct, no block_properties join). */
{ type: "TodoState"; state: string } |
/**  Filter blocks by priority column (direct, no block_properties join). */
{ type: "Priority"; level: string } |
/**  Filter blocks by due_date column with comparison operator. */
{ type: "DueDate"; op: CompareOp; value: string } | { type: "HasTag"; tag_id: string } | { type: "HasTagPrefix"; prefix: string } | { type: "Contains"; query: string } | { type: "CreatedInRange"; after: string | null; before: string | null } | { type: "BlockType"; block_type: string } |
/**  Filter by source page — include/exclude blocks based on their root page ancestor. */
{ type: "SourcePage"; included: string[]; excluded: string[] } | { type: "And"; filters: BacklinkFilter[] } | { type: "Or"; filters: BacklinkFilter[] } | { type: "Not"; filter: BacklinkFilter };

/**
 *  A group of backlinks from the same source page.
 *
 *  `blocks` is `ActiveBlockRow`-typed; same rationale as
 *  [`BacklinkQueryResponse::items`].
 */
export type BacklinkGroup = {
	page_id: string,
	page_title: string | null,
	blocks: ActiveBlockRow[],
	/**
	 *  `true` when this group held more than `MAX_BLOCKS_PER_GROUP`
	 *  matching backlinks and `blocks` was truncated to the cap (#380).
	 *  The response-level `total_count` / `filtered_count` are counted
	 *  before truncation, so the UI can show e.g. "showing first 200 of
	 *  N" for this source page.
	 */
	truncated?: boolean,
};

/**
 *  Response for a filtered backlink query, including total count.
 *
 *  `items` is `ActiveBlockRow`-typed because the backlink
 *  resolver filters deleted_at IS NULL` on every
 *  candidate source block (`backlink/query.rs::eval_backlink_query`,
 *  `eval_backlink_query_grouped`, `eval_unlinked_references`).
 */
export type BacklinkQueryResponse = {
	items: ActiveBlockRow[],
	next_cursor: string | null,
	has_more: boolean,
	total_count: number,
	filtered_count: number,
};

/**  Tagged union of sort modes for backlink queries. */
export type BacklinkSort = { type: "Created"; dir: SortDir } | { type: "PropertyText"; key: string; dir: SortDir } | { type: "PropertyNum"; key: string; dir: SortDir } | { type: "PropertyDate"; key: string; dir: SortDir };

/**
 *  Newtype wrapper around ULID for type safety and consistent serialisation.
 *  Stores the canonical uppercase Crockford base32 representation.
 *
 *  Primary type for block IDs. Type aliases below provide semantic names for
 *  non-block entity IDs (attachments, snapshots) that are also ULIDs.
 *
 *  **Deserialization normalizes to canonical Crockford base32** — any valid
 *  ULID string (lowercase, mixed-case) is accepted and stored in canonical
 *  uppercase form. This is critical for blake3 hash determinism.
 */
export type BlockId = string;

/**
 *  Row returned by paginated block queries.
 *
 *  Took the parallel-types path (over the explored
 *  `BlockRow<Id = String>` generic, which collided with two
 *  `specta-typescript` 0.0.11 constraints — no generic-default emit and
 *  `PLACEHOLDER_Id` codegen dropping `Id: Clone` bounds through embedded
 *  generic structs). `BlockRow` stays raw — used by polymorphic
 *  dispatchers (`list_blocks_inner`'s show-deleted/agenda/tag/by-type/
 *  children fan-out) and by helpers that intentionally surface conflict
 *  or deleted rows (`get_block`, `list_trash`). Helpers
 *  whose SQL filters `deleted_at IS NULL` return
 *  [`ActiveBlockRow`] instead and lift the activeness invariant into
 *  the type system at the helper signature.
 */
export type BlockRow = {
	id: BlockId,
	block_type: string,
	content: string | null,
	parent_id: BlockId | null,
	position: number | null,
	/**  Epoch-ms (blocks.deleted_at is INTEGER since migration 0080). */
	deleted_at: number | null,
	todo_state: string | null,
	priority: string | null,
	due_date: string | null,
	scheduled_date: string | null,
	page_id: BlockId | null,
};

/**  Metadata returned by [`collect_bug_report_metadata`]. */
export type BugReport = {
	app_version: string,
	os: string,
	arch: string,
	device_id: string,
	/**
	 *  Last [`RECENT_ERRORS_CAP`] error/warn lines from today's
	 *  `agaric.log`, newest last.
	 *
	 *  #609: ALWAYS redacted through the same pipeline as the ZIP export
	 *  ([`redact_line_with_redactor`]) — the frontend embeds these lines
	 *  verbatim into the prefilled PUBLIC GitHub issue body
	 *  (`src/lib/bug-report.ts::formatReportBody`), and unlike the ZIP
	 *  path there is no user-facing redact toggle on the issue-body path.
	 */
	recent_errors: string[],
};

export type BulkTrashResponse = {
	affected_count: number,
};

/**  Result of an op log compaction, returned by [`compact_op_log_cmd`]. */
export type CompactionResult = {
	snapshot_id: string | null,
	ops_deleted: number,
};

/**  Statistics about the op log, returned by [`get_compaction_status`]. */
export type CompactionStatus = {
	total_ops: number,
	oldest_op_date: number | null,
	eligible_ops: number,
	retention_days: number,
};

/**  Comparison operators for property filters. */
export type CompareOp = "Eq" | "Neq" | "Lt" | "Gt" | "Lte" | "Gte" | "Contains" | "StartsWith";

/**
 *  One row of [`create_blocks_batch_inner`]'s input list.
 *
 *  Mirrors the per-block argument set the FE used to send to `create_block`
 *  once per descendant / per markdown line in `template-utils.ts`. The
 *  `properties` map carries arbitrary `key -> value_text` pairs that land
 *  as `SetProperty` ops inside the same transaction (mirrors
 *  `import_markdown_inner`'s precedent — see `pages.rs:622-637`). Reserved
 *  keys (`todo_state` / `priority` / `due_date` / `scheduled_date`) route
 *  through the same `set_property_in_tx` helper so they hit the right
 *  columns on `blocks` instead of `block_properties`.
 */
export type CreateBlockSpec = {
	/**
	 *  `"content"`, `"tag"`, or `"page"`. Validated per-spec by
	 *  [`create_block_in_tx`] — an unknown value rolls back the whole
	 *  batch with [`AppError::Validation`].
	 */
	blockType: string,
	/**
	 *  Block content (markdown / plain text). Validated against
	 *  `MAX_CONTENT_LENGTH` per spec.
	 */
	content: string,
	/**
	 *  Optional parent block id. When `Some`, the parent must resolve
	 *  to a live (non-deleted, non-conflict) block — including parents
	 *  created EARLIER in the same batch. When `None`, the new block is
	 *  top-level.
	 */
	parentId: BlockId | null,
	/**
	 *  Optional 1-based sibling position (stable wire field). `None` appends
	 *  after the last sibling. #400: converted to the engine's 0-based sibling
	 *  `index` at the call site (position 1 → index 0).
	 */
	position: number | null,
	/**
	 *  Optional `key -> value_text` map. Each entry expands to a
	 *  `SetProperty` op inside the same transaction. Empty map → no
	 *  property ops appended. Mirror of the (key, value) loop in
	 *  `import_markdown_inner` for parsed markdown property lines.
	 */
	properties?: { [key in string]: string },
};

/**  The calendar granularity of a [`GroupKey::DateBucket`]. */
export type DateBucketUnit =
/**  One bucket per calendar day, rendered `YYYY-MM-DD`. */
"day" |
/**  One bucket per ISO-ish week, rendered `YYYY-Www` (`strftime('%Y-W%W')`). */
"week" |
/**  One bucket per calendar month, rendered `YYYY-MM`. */
"month";

/**  The date column / timestamp a [`GroupKey::DateBucket`] buckets over. */
export type DateField =
/**  `b.due_date` (TEXT ISO `YYYY-MM-DD`). */
"due" |
/**  `b.scheduled_date` (TEXT ISO `YYYY-MM-DD`). */
"scheduled" |
/**
 *  Creation time. Derived from the EARLIEST `op_log.created_at`
 *  (epoch-ms) for the block; blocks with no op-log row have no created
 *  date → the `"none"` bucket.
 */
"created" |
/**
 *  Last-edited time. Derived from the LATEST `op_log.created_at`
 *  (epoch-ms) for the block; same no-op-log rule as `Created`.
 */
"lastEdited";

/**
 *  Date-filter shape used by [`SearchFilter::due_filter`] /
 *  [`SearchFilter::scheduled_filter`].
 *
 *  Two variants:
 *
 *  - [`DateFilter::Named`] — bucket keyword resolved at query time
 *    against `chrono::Local::today()` (or the cell-injected clock in
 *    tests). Vocabulary: `overdue`, `today`, `yesterday`, `this-week`,
 *    `this-month`, `next-week`, `older`, `none`. Unknown keywords are
 *    rejected as `Validation("InvalidDateFilter: …")`.
 *  - [`DateFilter::Op`] — explicit comparison operator (`<`, `<=`, `=`,
 *    `>=`, `>`) followed by an ISO `YYYY-MM-DD` date. The frontend
 *    parser accepts the same shape (`due:>=2026-01-01`).
 *
 *  `#[serde(rename_all = "camelCase")]` on the enum variants keeps the
 *  wire shape ergonomic for the TS side: the AST projection emits
 *  `{ named: "today" }` or `{ op: { op: "gte", date: "2026-01-01" } }`.
 */
export type DateFilter =
/**  Named bucket — resolved to a date predicate at query time. */
({ named: NamedDateRange }) & { op?: never } |
/**  Explicit comparison operator + ISO date. */
({ op: {
	/**
	 *  One of [`DateOp::Lt`] / [`DateOp::Lte`] / [`DateOp::Eq`] /
	 *  [`DateOp::Gte`] / [`DateOp::Gt`].
	 */
	op: DateOp,
	/**
	 *  ISO `YYYY-MM-DD`. Calendar-validated at the SQL composition
	 *  boundary; invalid dates yield `Validation("InvalidDateFilter:
	 *  …")`.
	 */
	date: string,
} }) & { named?: never };

/**
 *  Comparison operator for [`DateFilter::Op`]. Mirrors the
 *  frontend parser shape (`<`, `<=`, `=`, `>=`, `>`).
 */
export type DateOp = "lt" | "lte" | "eq" | "gte" | "gt";

/**
 *  #1280 — a predicate over a TEXT-ISO date column (`blocks.due_date`,
 *  `blocks.scheduled_date`, or any `YYYY-MM-DD[...]` column). Comparisons
 *  are **lexical**: ISO-8601 dates sort the same byte-wise as
 *  chronologically, so `'2026-01-02' > '2026-01-01'` holds as a string
 *  compare.
 *
 *  Internally-tagged on `"type"` (PascalCase). The TS union reads
 *  `{ type: "IsNull" } | { type: "Before", date } | { type: "After", date }
 *  | { type: "OnOrBefore", date } | { type: "OnOrAfter", date }
 *  | { type: "On", date } | { type: "Between", from, to }`.
 *
 *  **`On` and the calendar-day rule:** `On YYYY-MM-DD` means "the whole
 *  calendar day". When the underlying column is *pure* `YYYY-MM-DD` (no
 *  time component) a lexical `= ?` already matches the whole day — that is
 *  the form [`BacklinkProjection::compile_due_date`] /
 *  [`compile_scheduled`](Projection::compile_scheduled) emit, byte-identical
 *  to the legacy backlink `DueDate{Eq}` leaf (the resolver oracle treats the
 *  column as DATE-exact). For a column that carries a *time* component the
 *  generic [`DatePredicate::to_lexical_sql`] expands `On` to the half-open
 *  day range `>= 'd' AND < 'd+1day'` so daytime values on the named day are
 *  included (mirroring `compile_last_edited`'s end-of-day handling).
 */
export type DatePredicate =
/**  The column is NULL (unset). */
{ type: "IsNull" } |
/**  Strictly before the given date (`< 'date'`). */
{ type: "Before"; date: string } |
/**  Strictly after the given date (`> 'date'`). */
{ type: "After"; date: string } |
/**  On or before the given date (`<= 'date'`). */
{ type: "OnOrBefore"; date: string } |
/**  On or after the given date (`>= 'date'`). */
{ type: "OnOrAfter"; date: string } |
/**
 *  Exactly on the given calendar day. See the type-level doc for the
 *  day-expansion rule.
 */
{ type: "On"; date: string } |
/**  Inclusive range `BETWEEN 'from' AND 'to'`. */
{ type: "Between"; from: string; to: string };

/**  A date range for agenda queries. Both fields must be in `YYYY-MM-DD` format. */
export type DateRange = {
	start: string,
	end: string,
};

export type DeleteResponse = {
	block_id: string,
	deleted_at: number,
	descendants_affected: number,
};

/**  A contiguous span of text with a diff tag. */
export type DiffSpan = {
	tag: DiffTag,
	value: string,
};

/**  Tag indicating what happened to a span of text. */
export type DiffTag = "Equal" | "Delete" | "Insert";

/**  A single draft row from `block_drafts`. */
export type Draft = {
	block_id: BlockId,
	content: string,
	/**  Epoch-ms (block_drafts.updated_at is INTEGER since migration 0082). */
	updated_at: number,
	/**
	 *  #1256: MONOTONIC supersession anchor. The local device's op-log
	 *  high-water (`MAX(seq)`) at the moment this draft was saved — "every op
	 *  up to this seq is already reflected in the draft's view." Recovery
	 *  treats the draft as superseded iff a block-scoped op exists with
	 *  `seq > draft_anchor_seq` on the same device (migration 0092).
	 *  `0` (the backfill default) means "no local op preceded this draft", so
	 *  any existing op supersedes it.
	 */
	draft_anchor_seq: number,
	/**
	 *  #1256: which device's per-device `seq` space `draft_anchor_seq` lives
	 *  in. `None` (legacy/backfill) is treated by the recovery query as
	 *  "matches the recovering device".
	 */
	draft_anchor_device: string | null,
};

/**
 *  Bundled extra filters for the [`query_by_property`] Tauri command.
 *
 *  Exists purely to keep `query_by_property`'s argument count under
 *  The `tauri-specta` 10-arg limit. added
 *  `exclude_parent_id` / `content_non_empty` (pushing this command
 *  To 9 IPC args incl. `pool`); adds another three
 *  (`block_type`, `value_text_in`, `value_date_range`). Bundling all
 *  five into one struct keeps the IPC arg count at 8.
 *
 *  The five sub-fields are still threaded into
 *  `query_by_property_inner` as individual parameters — bundling is a
 *  transport-layer concern. `None` means "no extra filter applies"
 *  (the common case); each sub-field remains optional inside the
 *  struct so callers can specify just one. The hand-written TS
 *  wrapper in `src/lib/tauri.ts` keeps the flat public API and
 *  marshals into this struct only at the IPC boundary, mirroring the
 *  [`AgendaQuery`] precedent on `list_blocks`.
 *
 *  Serde `rename_all = "camelCase"` matches the Tauri command-arg
 *  convention.
 */
export type ExtraQueryFilters = {
	/**
	 *  Exclude rows whose `parent_id` matches.
	 *  `IS NOT` semantics so NULL parents are kept.
	 */
	excludeParentId: string | null,
	/**
	 *  Drop rows whose content is NULL, empty, or
	 *  whitespace-only (matches FE `!b.content?.trim()`).
	 */
	contentNonEmpty: boolean | null,
	/**  Push `block_type = ?` into SQL. */
	blockType: string | null,
	/**
	 *  Push `value_text IN (...)` into SQL via
	 *  `json_each`. Mutually exclusive with `value_text` on
	 *  `query_by_property`.
	 */
	valueTextIn: string[] | null,
	/**
	 *  Push `value_date >= from AND value_date < to`
	 *  into SQL (half-open `[from, to)` range).
	 */
	valueDateRange: [string, string] | null,
	/**
	 *  #738 sub-2 — push `b.todo_state NOT IN (...)` into SQL so the
	 *  DuePanel's overdue query can exclude completed (`DONE`) tasks at
	 *  the database layer instead of post-filtering a capped page. NULL
	 *  `todo_state` rows are retained (only the listed states are
	 *  dropped). `None` / empty preserves the unfiltered behaviour.
	 */
	excludeTodoStates: string[] | null,
};

/**
 *  A boolean tree over [`FilterPrimitive`] leaves.
 *
 *  Struct variants (not newtype/tuple variants) for the same reason
 *  [`FilterPrimitive`] uses them: serde's internally-tagged representation
 *  (`#[serde(tag = "type")]`) does not support newtype variants wrapping a
 *  non-struct, and named fields give the TS union self-describing shapes
 *  (`{ type: "Not", child }`).
 */
export type FilterExpr =
/**  A single primitive leaf. */
{ type: "Leaf"; primitive: FilterPrimitive } |
/**  Conjunction — every child must match. Empty = TRUE (`1=1`). */
{ type: "And"; children: FilterExpr[] } |
/**  Disjunction — at least one child must match. Empty = FALSE (`1=0`). */
{ type: "Or"; children: FilterExpr[] } |
/**  Set complement of the child (3-valued `NOT COALESCE((…), 0)`). */
{ type: "Not"; child: FilterExpr };

/**
 *  One filter atom in a compound-filter expression. Variants are tagged
 *  so the cross-surface SQL composer can dispatch via match.
 *
 *  **Wire shape (Phase 3):** internally-tagged on `"type"` with
 *  PascalCase variant names, matching `BacklinkFilter`. Every variant is
 *  a struct variant (single-field where the prior backend-only shape used
 *  a newtype) because `serde`'s internally-tagged representation does not
 *  support newtype variants wrapping a primitive — and struct variants
 *  give the frontend a self-describing field name (`{ type: "Tag", tag }`
 *  rather than a bare positional value).
 */
export type FilterPrimitive =
/**  Shared — block carries this tag id directly. */
{ type: "Tag"; tag: string } |
/**
 *  Shared — block carries `tag` via an ATTACHED `block_tags` row OR an
 *  inline `block_tag_refs` reference (`source_id`). The ref-inclusive tag
 *  semantics the legacy `query_by_tags`/`filtered_blocks_query` paths use;
 *  `Tag` is attached-only.
 */
{ type: "TagOrRef"; tag: string } |
/**
 *  Shared — block's `parent_id` equals `parent` (its direct children).
 *  Mirrors the legacy `list_blocks(parent_id=…)` backlinks path.
 */
{ type: "ChildOf"; parent: string } |
/**
 *  Shared — page name matches the GLOB pattern. `exclude=true`
 *  becomes a `NOT IN (...)` sub-select; otherwise an `IN (...)`.
 */
{ type: "PathGlob"; pattern: string; exclude: boolean } |
/**
 *  Shared — block carries a property matching this predicate.
 *
 *  D8 (make invalid states unrepresentable): the predicate is a
 *  single nested [`PropertyPredicate`] enum rather than a separate
 *  `op` + `Option<value>` pair. This guarantees by construction that
 *  `Eq`/`Ne` ALWAYS carry a value and `Exists`/`NotExists` NEVER do —
 *  the "partial" states (`Eq` with no value, `Exists` with a value)
 *  are simply not expressible, so `compile_has_property` no longer
 *  needs an `unsupported()` fallback.
 */
{ type: "HasProperty"; key: string; predicate: PropertyPredicate } |
/**  Shared — block's `last_modified_at` falls in this window. */
{ type: "LastEdited"; spec: LastEditedSpec } |
/**  Shared — block's owning page lives in this space. */
{ type: "Space"; space_id: string } |
/**
 *  Shared — block's `priority` is in `values` (or IS NULL when
 *  `is_null`). `exclude=true` negates the membership test. Multi-value
 *  to support the chip vocabulary; the single-value backlink `Priority`
 *  leaf routes to `{ values: [priority], is_null: false, exclude: false }`.
 */
{ type: "Priority"; values: string[]; is_null?: boolean; exclude?: boolean } |
/**
 *  #1280 — block's `todo_state` is in `values` (or IS NULL when
 *  `is_null`). `exclude=true` negates the membership test. Multi-value
 *  to support the chip vocabulary; the single-value backlink `TodoState`
 *  leaf routes to `{ values: [state], is_null: false, exclude: false }`.
 */
{ type: "State"; values: string[]; is_null?: boolean; exclude?: boolean } |
/**
 *  #1280 — block's `block_type` is in `values`. `exclude=true` negates.
 *  The single-value backlink `BlockType` leaf routes to
 *  `{ values: [block_type], exclude: false }`.
 */
{ type: "BlockType"; values: string[]; exclude: boolean } |
/**  #1280 — block's `due_date` matches the date predicate. */
{ type: "DueDate"; predicate: DatePredicate } |
/**  #1280 — block's `scheduled_date` matches the date predicate. */
{ type: "Scheduled"; predicate: DatePredicate } |
/**
 *  #1280 — block was created (by ULID-prefix range) at or after `after`
 *  and before `before`. Bounds are ISO dates; the projection converts
 *  each to a ULID prefix and compares `b.id`. Routes the backlink
 *  `CreatedInRange` leaf.
 */
{ type: "Created"; after: string | null; before: string | null } |
/**
 *  #1455 — block has an OUTBOUND link to the concrete `target` block id:
 *  `EXISTS (SELECT 1 FROM block_links l WHERE l.source_id = b.id AND
 *  l.target_id = ?)`. The richer "target is itself a `FilterExpr`" form
 *  is a deliberate follow-up; this leaf takes a concrete id.
 */
{ type: "LinksTo"; target: string } |
/**
 *  #1455 — block has an INBOUND link FROM the concrete `source` block id
 *  (inverse of [`LinksTo`]): `EXISTS (SELECT 1 FROM block_links l WHERE
 *  l.target_id = b.id AND l.source_id = ?)`. The richer FilterExpr-source
 *  form is a follow-up; this leaf takes a concrete id.
 */
{ type: "LinkedFrom"; source: string } |
/**
 *  #1455 — block's PARENT row satisfies the nested `matcher` expression:
 *  `EXISTS (SELECT 1 FROM blocks p WHERE p.id = b.parent_id AND
 *  (<matcher compiled against the parent row `p`>))`. The boxed
 *  [`FilterExpr`] is compiled against the parent alias `p` rather than the
 *  outer `b`. Recursion (a `HasParentMatching` whose matcher itself
 *  contains another `HasParentMatching`) is bounded by
 *  [`FilterExpr::MAX_DEPTH`](crate::filters::FilterExpr::MAX_DEPTH): the
 *  depth gate descends into the boxed matcher (#1455), so the compile
 *  recursion cannot run away.
 */
{ type: "HasParentMatching"; matcher: FilterExpr } |
/**
 *  Pages-only — page has no inbound links AND no outbound links.
 *  (`HasNoInboundLinks` is the looser inbound-only sibling.)
 */
{ type: "Orphan" } |
/**
 *  Pages-only — page has zero non-title descendants. Per
 *  "Page
 *  whose only block is its own title row (zero non-title
 *  descendants)". Backed by `pages_cache.child_block_count == 0`.
 */
{ type: "Stub" } |
/**  Pages-only — page has no inbound links (looser than `Orphan`). */
{ type: "HasNoInboundLinks" } |
/**  Search-only — regex pattern over block content. */
{ type: "Regex"; pattern: string } |
/**  Search-only — case-sensitive match toggle (post-FTS filter). */
{ type: "CaseSensitive"; enabled: boolean } |
/**  Search-only — whole-word match toggle (ASCII `\b` semantics). */
{ type: "WholeWord"; enabled: boolean } |
/**  Search-only — FTS5 `snippet()` window spec. */
{ type: "Snippet"; spec: SnippetSpec };

/**
 *  Result of [`flush_all_drafts_inner`]: how many drafts were processed
 *  inside the single transaction.
 *
 *  Returned by the boot-recovery one-IPC flush so the
 *  frontend can surface a recovery toast / log line.
 */
export type FlushAllDraftsResult = {
	/**
	 *  Number of drafts processed and removed from `block_drafts`.
	 *  Includes drafts that were dropped as orphans (target block missing
	 *  or soft-deleted) — anything that consumed a draft row counts.
	 */
	flushed: number,
};

/**
 *  The dimension an advanced query groups by. Internally-tagged on `"type"`.
 *
 *  Every variant resolves to a fixed SQL group-key expression built from
 *  STATIC column literals; the only user-controlled inputs are bound as `?`
 *  parameters ([`GroupKey::Property`]'s `key`, [`GroupKey::DateBucket`]'s
 *  `source`/`unit` — and `unit` maps to a literal `strftime` format, never
 *  interpolated). No user string is ever spliced in as an identifier, so
 *  grouping cannot inject SQL.
 *
 *  **Multiplicity:** [`GroupKey::Tag`] is the only MULTI-valued key — a
 *  block with K tags lands in K groups. All others are single-valued.
 */
export type GroupKey =
/**
 *  Group by tag (`block_tags.tag_id`). Joins `block_tags`, so a block
 *  appears once per tag it carries (documented multiplicity).
 */
{ type: "Tag" } |
/**
 *  Group by owning page (`b.page_id`). Blocks with no page bucket under
 *  the rendered key `"none"`.
 */
{ type: "Page" } |
/**
 *  Group by todo state (`b.todo_state`); NULL state → the `"none"`
 *  bucket.
 */
{ type: "State" } |
/**  Group by block type (`b.block_type`), always non-NULL. */
{ type: "BlockType" } |
/**  Group by priority (`b.priority`); NULL → the `"none"` bucket. */
{ type: "Priority" } |
/**
 *  Group by a typed property's `value_text` (correlated lookup on
 *  `block_properties` keyed by `key`); blocks lacking the property →
 *  the `"none"` bucket. `key` is BOUND as a `?` parameter.
 */
{ type: "Property";
/**  The property key to read `value_text` for. */
key: string } |
/**
 *  Group by a calendar bucket over a date column. `source` selects the
 *  column / op-log timestamp; `unit` selects the `strftime` granularity.
 *  Blocks with no date in the source → the `"none"` bucket.
 */
{ type: "DateBucket";
/**  Which date the bucket is computed over. */
source: DateField;
/**  The calendar granularity (day / ISO-week / month). */
unit: DateBucketUnit };

/**
 *  A grouping directive: bucket the matched rows by ONE dimension.
 *
 *  C4 will extend this with per-group aggregates; for now it carries only
 *  the [`GroupKey`].
 */
export type GroupSpec = {
	/**  The dimension to bucket by. */
	key: GroupKey,
};

/**  Response for grouped backlink queries — backlinks organized by source page. */
export type GroupedBacklinkResponse = {
	groups: BacklinkGroup[],
	next_cursor: string | null,
	has_more: boolean,
	total_count: number,
	filtered_count: number,
	/**
	 *  `true` when the FTS query hit the internal row cap (10 000) and results
	 *  may be incomplete.  Only relevant for unlinked-reference queries; regular
	 *  grouped backlink queries always set this to `false`.
	 */
	truncated: boolean,
};

/**  Row returned by block history queries (op_log entries for a block). */
export type HistoryEntry = {
	device_id: string,
	seq: number,
	op_type: string,
	payload: string,
	/**  Epoch-ms (op_log.created_at is INTEGER since migration 0079). */
	created_at: number,
};

/**
 *  Streaming progress payload for a single `import_markdown` call (#128).
 *
 *  Carried over a Tauri `Channel<ImportProgressUpdate>` so a long import
 *  can render a per-block progress bar instead of a bare spinner. The
 *  enum is `Serialize` + `Type` only (no `Deserialize`) — like
 *  [`crate::sync_events::SyncProgressUpdate`], it is a one-way
 *  backend→frontend payload. Frontend consumers switch on `kind` and read
 *  the variant-specific fields.
 *
 *  Emission contract (see `import_markdown_inner`): exactly one
 *  [`Started`](ImportProgressUpdate::Started) before any block is written,
 *  one [`Progress`](ImportProgressUpdate::Progress) per block created, and
 *  exactly one [`Complete`](ImportProgressUpdate::Complete) — but ONLY
 *  after the enclosing transaction commits. A failed import emits
 *  `Started` + zero-or-more `Progress` and then NO `Complete` (the command
 *  returns `Err`), so a consumer that never sees `Complete` must treat the
 *  import as failed.
 */
export type ImportProgressUpdate =
/**
 *  Emitted once, before the first block is created. `blocks_total` is
 *  the parser's block count, so the UI can render a determinate bar
 *  from the very first event. May be 0 for an empty / headings-only
 *  file.
 */
{ kind: "started";
/**  Title derived from the filename (or the fallback). */
page_title: string;
/**  Total blocks the parser produced for this file. */
blocks_total: number } |
/**
 *  Emitted after each block is created inside the transaction.
 *  `blocks_done` counts up to `blocks_total`.
 */
{ kind: "progress"; blocks_done: number; blocks_total: number } |
/**
 *  Emitted once, AFTER the transaction commits successfully. Mirrors
 *  the returned [`ImportResult`] counts so a consumer can render the
 *  final state from the channel alone.
 */
{ kind: "complete"; page_title: string; blocks_created: number; properties_set: number };

/**
 *  Outcome of importing one markdown file: the created page plus aggregate
 *  counts and any non-fatal diagnostics, returned by
 *  [`import_markdown_with_progress`] and surfaced to the import UI.
 */
export type ImportResult = {
	/**
	 *  Title of the page block the import created (derived from the filename
	 *  or the file's leading heading).
	 */
	page_title: string,
	/**  Number of content blocks made durable by the import. */
	blocks_created: number,
	/**
	 *  Number of page-level properties stamped onto the created page (e.g.
	 *  from YAML frontmatter).
	 */
	properties_set: number,
	/**
	 *  Non-fatal diagnostics collected while importing. Carries both soft
	 *  parse warnings (e.g. depth clamping, stripped `((block-ref))` tokens,
	 *  ambiguous wiki-links left as plain text) and per-item skip notices
	 *  (e.g. a frontmatter ref property that could not resolve to a page).
	 *  Empty on a fully clean import. Surfaced to the user and logged at
	 *  `warn!` on completion so a lossy import is never silent.
	 */
	warnings: string[],
};

/**
 *  `last-edited:` time-window spec.
 *
 *  Internally-tagged on `"type"` (PascalCase) so the TS union reads
 *  `{ type: "Rolling", days } | { type: "Range", start, end }
 *  | { type: "OlderThan", days }`.
 *
 *  Phase 2 review — the existing variants already cover the
 *  Plan's full bucket vocabulary (pending/-pages-view-compound-
 *  filters.md:144, lines 308-310). No `LastEditedBucket` variant is
 *  needed — the parser maps each chip token to one of these variants:
 *
 *  | Chip token                | Variant               |
 *  |---------------------------|-----------------------|
 *  | `last-edited:today`       | `Rolling { days: 1 }`  |
 *  | `last-edited:this-week`   | `Rolling { days: 7 }`  |
 *  | `last-edited:this-month`  | `Rolling { days: 30 }` |
 *  | `last-edited:older`       | `OlderThan { days: 30 }` |
 *  | `last-edited:>=YYYY-MM-DD` | `Range { .. }`        |
 */
export type LastEditedSpec =
/**
 *  Rolling N-days window. `Today`, `ThisWeek`, `ThisMonth` map to
 *  1 / 7 / 30. Custom values are accepted but documented as
 *  "rolling, not calendar".
 */
{ type: "Rolling"; days: number } |
/**  Absolute date range (ISO 8601 dates, inclusive on both ends). */
{ type: "Range"; start: string; end: string } |
/**
 *  Older than the given rolling N-days window (the inverse of
 *  `Rolling`). Used by `last-edited:older` chip.
 */
{ type: "OlderThan"; days: number };

export type LinkMetadata = {
	url: string,
	title: string | null,
	favicon_url: string | null,
	description: string | null,
	/**
	 *  Milliseconds since the UNIX epoch (UTC) — see `crate::db::now_ms`.
	 *  Exposed to the frontend as a `number` (#109 Phase 2; was an RFC 3339
	 *  string before the INTEGER-ms timestamp migration).
	 */
	fetched_at: number,
	auth_required: boolean,
	/**
	 *  (follow-up): `true` when the most recent
	 *  fetch saw a terminal "this resource is gone" status (HTTP 404 or
	 *  410). Distinct from `auth_required` (401/403, transient
	 *  sign-in) and from "transient" (5xx — both flags false plus
	 *  `title.is_none()`). The frontend uses this to render a "(not
	 *  found)" tag and suppress the favicon.
	 *
	 *  `#[serde(default)]` so any legacy serialized blob — e.g. a
	 *  cached snapshot deserialized before this field existed — keeps
	 *  deserializing cleanly as `false`.
	 */
	not_found?: boolean,
};

/**  Filter / sort bundle for [`list_pages_with_metadata`]. */
export type ListPagesWithMetadataFilter = {
	sort?: PageSort,
	spaceId: string,
	/**
	 *  Phase 3 — compound filter primitives applied server-side,
	 *  AND-joined into the WHERE before the keyset/ORDER BY/LIMIT. Empty
	 *  (the default) preserves the pre- "no filter" behaviour, so
	 *  existing callers and the flag-off path are unaffected. Each
	 *  primitive is gated against [`PagesProjection::allowed_keys`] and
	 *  rejected with [`AppError::Validation`] if it is not a Pages-surface
	 *  token (defence-in-depth — the frontend never sends Search-only
	 *  primitives, but the backend must not trust that).
	 */
	filters?: FilterPrimitive[],
};

/**  One log file's name + contents returned by [`read_logs_for_report`]. */
export type LogFileEntry = {
	name: string,
	contents: string,
};

/**
 *  Match span emitted by the toggle pipeline.
 *
 *  The `start` / `end` indices are **UTF-16 code-unit offsets** into the
 *  block's content string — chosen to match JavaScript's native string
 *  indexing (`.length`, `.substring`, `.charCodeAt`). Rust's `regex`
 *  crate reports byte offsets into a UTF-8 buffer; the post-filter
 *  pipeline converts to UTF-16 before serialising so the frontend can
 *  slice `row.content` directly. ASCII content has identical byte /
 *  UTF-16 indices; CJK and emoji content does not. See
 *  (UTF-8 → UTF-16 section)
 *  for the rationale and the conversion helper.
 */
export type MatchOffset = {
	/**  UTF-16 code-unit offset (matches JavaScript string indexing). */
	start: number,
	/**  UTF-16 code-unit offset (matches JavaScript string indexing). */
	end: number,
};

/**
 *  Snapshot of the MCP **read-write** server state surfaced to the
 *  Settings tab. Identical fields to [`McpStatus`] but a distinct type so
 *  the Tauri command surface stays RO / RW symmetric and the frontend
 *  can present them as separate toggles.
 */
export type McpRwStatus = {
	enabled: boolean,
	socket_path: string,
	active_connections: number,
};

/**
 *  Snapshot of the MCP RO server state surfaced to the Settings tab.
 *
 *  `socket_path` is a display string on every platform (the Unix socket
 *  filesystem path on Linux / macOS, the named-pipe path on Windows).
 *  `active_connections` reports the instantaneous count from
 *  [`McpLifecycle::connection_count`] — it is not a rolling average.
 */
export type McpStatus = {
	enabled: boolean,
	socket_path: string,
	active_connections: number,
};

export type MoveResponse = {
	block_id: string,
	new_parent_id: string | null,
	new_position: number,
};

/**
 *  Named date buckets recognised by [`DateFilter::Named`].
 *
 *  Resolution semantics (today = `chrono::Local::today()`):
 *
 *  - `Overdue`   → column `< today AND column IS NOT NULL`.
 *  - `Today`     → column `= today`.
 *  - `Yesterday` → column `= today - 1d`.
 *  - `ThisWeek`  → column `BETWEEN start_of_week AND end_of_week` (Mon..Sun).
 *  - `ThisMonth` → column `BETWEEN start_of_month AND end_of_month`.
 *  - `NextWeek`  → column `BETWEEN start_of_next_week AND end_of_next_week`.
 *  - `Older`     → column `< today - 30d AND column IS NOT NULL`.
 *  - `None`      → column `IS NULL`. Used by `state:none` analogue —
 *    "show blocks with no scheduled/due date".
 */
export type NamedDateRange = "overdue" | "today" | "yesterday" | "this-week" | "this-month" | "next-week" | "older" | "none";

/**  Reference to a specific op in the log. */
export type OpRef = {
	device_id: string,
	seq: number,
};

/**
 *  Page header for callers that need every page in a space without
 *  pagination.  Used by the markdown export (`exportGraphAsZip`) and by
 *  the graph view, which both want the full set in one shot.
 *
 *  Includes the four agenda-shaped native columns on `blocks`
 *  (`todo_state` / `priority` / `due_date` / `scheduled_date`) because
 *  the graph node renderer keys node colour / icons on them.  The
 *  markdown exporter ignores them.
 */
export type PageHeading = {
	id: BlockId,
	content: string | null,
	todo_state: string | null,
	priority: string | null,
	due_date: string | null,
	scheduled_date: string | null,
};

/**
 *  A block id in its role as a page reference.
 *
 *  Read a `page_id` TEXT column into this type when the value names a page
 *  (or the owning page of a block). It is a drop-in replacement for
 *  reading the column as [`BlockId`] / `String`.
 *
 *  **Wire-format parity with [`BlockId`] / `String`:** `serde` uses
 *  `transparent` and `sqlx::Type` is `transparent` over the inner
 *  [`BlockId`] (itself transparent over `String`) — the encoded
 *  representation is byte-identical to the underlying ULID. Round-tripping
 *  through JSON / SQLite preserves the value exactly.
 */
export type PageId = BlockId;

/**
 *  A link between two pages (for graph visualization).
 *
 *  Both endpoints are [`ActiveBlockId`] — `list_page_links_inner` filters
 *  deleted_at IS NULL` on both source and target
 *  Pages (lift of invariant #9 into the type system).
 */
export type PageLink = {
	source_id: ActiveBlockId,
	target_id: ActiveBlockId,
	ref_count: number,
};

/**
 *  Boolean facts about a page's contents (Review Round 1: replaces a
 *  `has_property_flags: i64` bitmask). Each field maps 1:1 to an
 *  `EXISTS` subquery in the metadata SELECT. Adding a new flag is
 *  purely additive — new `bool` column, no consumer surprises.
 */
export type PagePropertyFlags = {
	/**  Page itself carries a `block_tags` row. */
	hasTags: boolean,
	/**  At least one descendant has a non-NULL `todo_state`. */
	hasTodo: boolean,
	/**  At least one descendant has a non-NULL `scheduled_date`. */
	hasScheduled: boolean,
	/**  At least one descendant has a non-NULL `due_date`. */
	hasDue: boolean,
};

/**
 *  Paginated response.
 *
 *  `total_count` is `Option<i64>` because cursor pagination does not in
 *  general require a count and most pagination helpers leave it `None`
 *  (the FE detects the end of results via `has_more = false`). A small
 *  number of list surfaces compute it via a dedicated `COUNT(*)` query
 *  and surface "X of Y" progress to the user — `list_blocks_inner`
 *  (when filtering on `block_type`) is the first such site (PageBrowser
 *  pagination UX, 2026-05-14). Helpers that do not compute the count
 *  flow through [`build_page_response`] which initialises the field to
 *  `None`; sites that compute it use
 *  [`build_page_response_with_total`].
 */
export type PageResponse<T> = {
	items: T[],
	next_cursor: string | null,
	has_more: boolean,
	/**
	 *  Total number of matching rows in the underlying table, ignoring
	 *  the page cursor/limit. `None` when the helper does not compute
	 *  it (the default). Populated by surfaces that drive an "X of Y"
	 *  progress indicator.
	 *
	 *  Always serialised (no `skip_serializing_if`) so the wire format
	 *  matches the TS type `number | null` exactly — consumers read
	 *  `total_count` directly without having to check for an absent key.
	 */
	total_count: number | null,
};

/**
 *  Sort mode for [`list_pages_with_metadata_inner`].
 *
 *  These are the server-derived sort modes the IPC exposes. The
 *  frontend may layer two additional sorts that don't go over the wire:
 *
 *    - `recent` — per-device visit history (sourced from `getRecentPages()`).
 *    - `created` — ULID DESC (just `Default` reversed in JS).
 *
 *  Both reuse the `Default` SQL ordering and re-sort the loaded page
 *  client-side.
 */
export type PageSort =
/**  Title ascending, case-insensitive. Default for "browse my pages". */
"alphabetical" |
/**  Last-modified timestamp (max op_log.created_at) DESC. */
"recently-modified" |
/**  Inbound-link count DESC (page + descendant link targets). */
"most-linked" |
/**  Descendant-block count DESC. */
"most-content" |
/**
 *  Default backend ordering — block id ASC. Useful for debugging
 *  and as the wire shape for the frontend-only `recent` / `created`
 *  sorts that re-sort client-side.
 */
"default";

/**
 *  Result of [`load_page_subtree_inner`] — the (possibly capped) block
 *  set plus an honest truncation signal so the FE can surface a
 *  non-blocking notice instead of silently dropping descendants.
 *
 *  #1258 — the loader caps its returned set at [`PAGE_SUBTREE_MAX_BLOCKS`]
 *  by flat `(position, id)` order, which is NOT structure-preserving: a
 *  surviving deeply-nested child whose parent row was cut becomes an
 *  orphan that `buildFlatTree`'s DFS can never reach. Before, the only
 *  response was a backend `tracing::warn`; the user saw a page missing
 *  arbitrary blocks with no signal. We now carry `total` (the true active
 *  descendant count, computed independently of the cap) and `truncated`
 *  (`total > returned`) so the FE can tell the user "showing the first
 *  N of M".
 */
export type PageSubtree = {
	/**  The (possibly capped) active descendant rows, excluding the root. */
	blocks: BlockRow[],
	/**
	 *  True when the page has more active descendants than were returned —
	 *  i.e. the [`PAGE_SUBTREE_MAX_BLOCKS`] cap fired and some blocks were
	 *  dropped from `blocks`.
	 */
	truncated: boolean,
	/**
	 *  The true count of active descendants under the root (excluding the
	 *  root and soft-deleted blocks), computed independently of the cap.
	 *  `blocks.len()` is `min(total, PAGE_SUBTREE_MAX_BLOCKS)`.
	 */
	total: number,
};

/**
 *  Row returned by [`list_pages_with_metadata_inner`].
 *
 *  Carries every `BlockRow` column verbatim so the frontend can read
 *  `id`, `content`, etc. via the same accessors. Four extra metadata
 *  columns drive the new sort modes + density badges.
 */
export type PageWithMetadataRow = {
	id: BlockId,
	blockType: string,
	content: string | null,
	parentId: BlockId | null,
	position: number | null,
	deletedAt: number | null,
	todoState: string | null,
	priority: string | null,
	dueDate: string | null,
	scheduledDate: string | null,
	pageId: PageId | null,
	/**
	 *  max(`op_log.created_at`) over the page itself, as INTEGER
	 *  epoch-milliseconds (#109 Phase 2). None if the page has no op-log
	 *  entries (which should never happen — every active page has at
	 *  least its own creation row — but the column is `Option` to absorb
	 *  edge cases like manually-imported rows without a synthesised
	 *  op-log entry).
	 */
	lastModifiedAt: number | null,
	/**
	 *  COUNT of `block_links` targeting this page or any of its
	 *  descendants. Always emitted (zero for un-linked pages).
	 */
	inboundLinkCount: number,
	/**
	 *  COUNT of non-deleted descendants (blocks where `page_id = id`,
	 *  excluding the page itself). Always emitted.
	 */
	childBlockCount: number,
	/**
	 *  Typed flag struct (Review Round 1: replaces the prior
	 *  `has_property_flags: i64` bitmask — see [`PagePropertyFlags`]).
	 */
	flags: PagePropertyFlags,
};

/**
 *  Response payload returned by [`start_pairing`].
 *
 *  The QR payload + [`PairingInfo`] both carry only the passphrase.
 *  mDNS owns discovery + address resolution end-to-end; there is no
 *  scan-bootstrap path that would need a `host`/`port` here.
 */
export type PairingInfo = {
	passphrase: string,
	qr_svg: string,
};

/**
 *  Response envelope for [`search_blocks_partitioned`].
 *
 *  Carries two partitions of the same FTS scan in one IPC round-trip:
 *
 *  - `pages` — rows where `block_type == "page"`, capped at the
 *    caller's `page_limit`.
 *  - `blocks` — the **unrestricted** rank-ordered set (may include
 *    page-typed rows alongside content), capped at the caller's
 *    `block_limit`. The palette intentionally shows both together in
 *    this partition; the dedicated `pages` partition is for the
 *    page-group rendering.
 *
 *  Neither partition emits a cursor (the palette doesn't paginate) and
 *  `total_count` is always `None`. The `has_more` flag is set per
 *  partition — see [`search_blocks_partitioned`] for the exact
 *  semantics.
 */
export type PartitionedSearchResponse = {
	/**  Rows with `block_type = 'page'`, capped at `page_limit`. */
	pages: PageResponse<SearchBlockRow>,
	/**
	 *  Unrestricted rank-ordered rows (any `block_type`), capped at
	 *  `block_limit`. May overlap with [`Self::pages`] — the palette
	 *  merges them client-side.
	 */
	blocks: PageResponse<SearchBlockRow>,
};

/**  A row from the `peer_refs` table representing a remote sync peer. */
export type PeerRef = {
	peer_id: string,
	last_hash: string | null,
	last_sent_hash: string | null,
	/**
	 *  Most recent successful sync, in milliseconds since the UNIX epoch
	 *  (UTC); `None` = never synced. #109 Phase 2: was an RFC 3339 string.
	 */
	synced_at: number | null,
	reset_count: number,
	/**
	 *  Most recent protocol reset, in milliseconds since the UNIX epoch
	 *  (UTC); `None` = never reset. #109 Phase 2: was an RFC 3339 string.
	 */
	last_reset_at: number | null,
	/**
	 *  SHA-256 hex of the peer's TLS certificate, observed during pairing.
	 *  Used for certificate pinning on reconnection.
	 */
	cert_hash: string | null,
	/**  Human-readable name/label for this peer (e.g. "Javier's Phone"). */
	device_name: string | null,
	/**
	 *  Last known network address (host:port) for direct connection.
	 *  Updated after each successful sync. Used when mDNS is unavailable.
	 */
	last_address: string | null,
};

/**  A property definition from the schema registry. */
export type PropertyDefinition = {
	key: string,
	value_type: string,
	options: string | null,
	created_at: string,
};

/**
 *  One property predicate for [`filtered_blocks_query_inner`].
 *
 *  Mirrors the per-call shape of [`query_by_property_inner`] so a caller
 *  migrating from the JS-side AND-intersection (`Promise.all` over N
 *  `query_by_property` IPCs) can replay each sub-filter unchanged. Each
 *  instance becomes ONE `EXISTS (SELECT 1 FROM block_properties bp …)`
 *  subquery in the composed SQL — the AND-intersection is the
 *  structural conjunction of the EXISTS clauses (no JS post-filter, no
 *  silent row cap).
 *
 *  At most one of `value_text` / `value_text_in` / `value_date` /
 *  `value_date_range` should be supplied per filter; mixing them is
 *  rejected with [`AppError::Validation`] at the boundary (mirrors the
 *  `query_by_property` contract).
 */
export type PropertyFilter = {
	/**
	 *  Property key — `block_properties.key` or a reserved column name
	 *  (`todo_state`, `priority`, `due_date`, `scheduled_date`).
	 */
	key: string,
	/**
	 *  Single text-value equality / comparison. Mutually exclusive with
	 *  `value_text_in`.
	 */
	valueText: string | null,
	/**
	 *  Set-membership over text values, bound as a JSON array via
	 *  `json_each(?N)`. Empty = treated as `None`.
	 */
	valueTextIn?: string[],
	/**  Single date-value equality / comparison. */
	valueDate: string | null,
	/**  Half-open `[from, to)` date range. */
	valueDateRange: [string, string] | null,
	/**
	 *  Comparison operator — `"eq"`, `"neq"`, `"lt"`, `"gt"`, `"lte"`,
	 *  `"gte"`. Defaults to `"eq"` for any unrecognised value.
	 */
	operator?: string,
};

/**
 *  Predicate on a `has-property:` primitive.
 *
 *  D8 (make invalid states unrepresentable): a single internally-tagged
 *  enum that fuses the operator with its operand. `Eq`/`Ne` carry a
 *  mandatory [`PropertyValue`]; `Exists`/`NotExists` carry none. The
 *  previous shape — `op: PropertyOp` plus `value: Option<PropertyValue>`
 *  — admitted two nonsensical combinations (`Eq` with no value, `Exists`
 *  with a value) that had to be rejected at compile time with an
 *  `unsupported()` sentinel. Folding the operand into the operator
 *  variant removes those states from the type entirely.
 *
 *  **Wire shape:** internally-tagged on `"type"` (PascalCase) so the TS
 *  union reads `{ type: "Exists" } | { type: "NotExists" }
 *  | { type: "Eq", value: PropertyValue } | { type: "Ne", value: PropertyValue }`.
 */
export type PropertyPredicate =
/**  Property key exists (no value comparison). */
{ type: "Exists" } |
/**  Property key does NOT exist. */
{ type: "NotExists" } |
/**
 *  Property value equals the given operand. `Text` compares
 *  `value_text`; `Ref` compares `value_ref`.
 */
{ type: "Eq"; value: PropertyValue } |
/**
 *  Property value does NOT equal the given operand (the block has no
 *  matching `(key, value)` row). `Text` compares `value_text`; `Ref`
 *  compares `value_ref`.
 */
{ type: "Ne"; value: PropertyValue } |
/**
 *  #1280 — property value is strictly less than the operand. The
 *  compared column is chosen from the [`PropertyValue`] variant (see
 *  [`property_value_column`]).
 */
{ type: "Lt"; value: PropertyValue } |
/**  #1280 — property value is strictly greater than the operand. */
{ type: "Gt"; value: PropertyValue } |
/**  #1280 — property value is less than or equal to the operand. */
{ type: "Lte"; value: PropertyValue } |
/**  #1280 — property value is greater than or equal to the operand. */
{ type: "Gte"; value: PropertyValue } |
/**
 *  #1280 — property value contains the operand as a substring
 *  (`LIKE '%v%' ESCAPE '\'`). Meaningless on a `Num` value → `1=0`.
 */
{ type: "Contains"; value: PropertyValue } |
/**
 *  #1280 — property value starts with the operand (`LIKE 'v%' ESCAPE
 *  '\'`). Meaningless on a `Num` value → `1=0`.
 */
{ type: "StartsWith"; value: PropertyValue };

export type PropertyRow = {
	key: string,
	value_text: string | null,
	value_num: number | null,
	value_date: string | null,
	value_ref: string | null,
	/**
	 *  Native boolean property storage. SQLite represents booleans
	 *  as INTEGER (0/1, with a CHECK constraint allowing only NULL/0/1).
	 */
	value_bool: number | null,
};

/**
 *  The right-hand-side value type for `HasProperty`.
 *
 *  Internally-tagged on `"type"` (PascalCase) so the TS union reads
 *  `{ type: "Text", value } | { type: "Ref", value }`.
 */
export type PropertyValue = { type: "Text"; value: string } |
/**  References another block via `block_properties.value_ref`. */
{ type: "Ref"; value: string } |
/**
 *  #1280 — a numeric value compared against `block_properties.value_num`.
 *  Bound as [`Bind::Real`] so it keeps its native SQLite REAL affinity.
 */
{ type: "Num"; value: number | null } |
/**
 *  #1280 — an ISO-TEXT date value compared against
 *  `block_properties.value_date` (a TEXT column). Bound as
 *  [`Bind::Text`] — lexical ISO comparison, same as the backlink
 *  `PropertyDate` leaf.
 */
{ type: "Date"; value: string };

export type PurgeResponse = {
	block_id: string,
	purged_count: number,
};

/**
 *  One group bucket of a grouped advanced query.
 *
 *  `key` is the RENDERED group key — a tag id, page id, todo state /
 *  priority string, block type, date-bucket label (`YYYY-MM-DD` /
 *  `YYYY-Www` / `YYYY-MM`), or the literal `"none"` for the NULL/absent
 *  bucket. `count` is the FULL bucket size (every matched row in the group,
 *  not just the previewed members). `members` is a BOUNDED preview — the
 *  first N members in the engine's default sort — so a huge bucket cannot
 *  blow the payload; the full member list of one bucket is a follow-up
 *  "expand group" flat query scoped to that key.
 */
export type QueryGroup = {
	/**  The rendered group key (or `"none"` for the NULL/absent bucket). */
	key: string,
	/**  The full size of this bucket (independent of the member preview cap). */
	count: number,
	/**
	 *  A bounded preview of this bucket's member rows (at most
	 *  [`engine::GROUP_MEMBER_PREVIEW`]).
	 */
	members: QueryResultRow[],
	/**
	 *  Per-group aggregate results, in the SAME order as the request's
	 *  `aggregates`. Computed over THIS bucket's rows (the numeric-skip guard
	 *  applies). Empty when no aggregates were requested.
	 */
	aggregates?: AggregateResult[],
};

/**
 *  One row of an advanced-query page: a block plus its forward-compat
 *  ranking score.
 *
 *  `block` is flattened so the wire shape is `{ ...ActiveBlockRow, score }`
 *  — a stable superset of [`ActiveBlockRow`].
 */
export type QueryResultRow = {
	/**
	 *  The ranking channel. `Some(bm25)` when the request carried a
	 *  `fulltext` term (lower is a better match); `None` for purely
	 *  structural queries. A future vector pass may also fill it.
	 */
	score?: number | null,
} & ActiveBlockRow;

/**
 *  #1255: durable, user-visible boot-recovery status.
 *
 *  Emitted as the [`EVENT_RECOVERY_DEGRADED`] payload AND returned by the
 *  `get_recovery_status` command so a frontend that mounts after boot can
 *  still discover the degraded state. `degraded = true` means the boot
 *  op-log replay failed and the materialized view may be incomplete/stale
 *  — the app is still usable (the `op_log` is canonical) but the user
 *  should be warned before layering more writes on top.
 */
export type RecoveryStatus = {
	/**  `true` when the boot op-log replay failed wholesale. */
	degraded: boolean,
	/**
	 *  The replay error messages (the same as
	 *  [`RecoveryReport::replay_errors`]) for diagnostics / the bug-report
	 *  bundle. Empty when `degraded` is false.
	 */
	replay_errors: string[],
};

/**  Lightweight metadata returned by [`batch_resolve_inner`]. */
export type ResolvedBlock = {
	id: string,
	/**  `content` column — page title, tag name, or content text (truncated). */
	title: string | null,
	block_type: string,
	deleted: boolean,
};

export type RestoreResponse = {
	block_id: string,
	restored_count: number,
};

/**  Result of a point-in-time restore operation. */
export type RestoreToOpResult = {
	/**  Number of ops that were successfully reverted. */
	ops_reverted: number,
	/**  Number of non-reversible ops (purge_block, delete_attachment) skipped. */
	non_reversible_skipped: number,
	/**  Individual undo results for each reverted op. */
	results: UndoResult[],
};

/**
 *  Response row for `search_blocks_inner`.
 *
 *  Mirrors `ActiveBlockRow` column-for-column so the wire format is a
 *  strict superset (every field in `ActiveBlockRow` is reproduced
 *  verbatim) and adds `snippet` — the FTS5 [`snippet`] window with
 *  #828 PUA sentinel boundaries (U+E000 open / U+E001 close) on every
 *  match span. The web UI parses the sentinels into React nodes (no
 *  `dangerouslySetInnerHTML`); the MCP search tool converts them back to
 *  `<mark>` / `</mark>` so the agent-facing contract is unchanged. See
 *  For the renderer contract.
 *
 *  Appends `match_offsets: Vec<MatchOffset>` for the
 *  regex/whole-word offset rendering path; `#[serde(default)]` keeps
 *  The wire shape additive (pre- frontends see an empty array
 *  from absent payloads and fall through to the snippet path).
 *
 *  [`snippet`]: https://www.sqlite.org/fts5.html#the_snippet_function
 */
export type SearchBlockRow = {
	id: ActiveBlockId,
	block_type: string,
	content: string | null,
	parent_id: string | null,
	position: number | null,
	/**
	 *  Epoch-ms (blocks.deleted_at is INTEGER since migration 0080). Always
	 *  `None` on search rows — the FTS SQL filters `deleted_at IS NULL` — but
	 *  typed as `i64` to match the rest of the #109 cluster.
	 */
	deleted_at: number | null,
	todo_state: string | null,
	priority: string | null,
	due_date: string | null,
	scheduled_date: string | null,
	page_id: string | null,
	/**
	 *  FTS5 `snippet()` window for the matched block. `None` when the
	 *  match has no content snippet (e.g. a page-title-only hit on a
	 *  block with `content IS NULL`). Contains #828 PUA sentinel
	 *  boundaries (U+E000 open / U+E001 close) around each match span —
	 *  the web UI parses these as React nodes (never
	 *  `dangerouslySetInnerHTML`); the MCP search tool converts them back
	 *  to `<mark>` / `</mark>`.
	 */
	snippet?: string | null,
	/**
	 *  UTF-16 code-unit match offsets for the toggle
	 *  pipeline. Populated when any of the three search toggles
	 *  (`case_sensitive` / `whole_word` / `is_regex`) is on and the
	 *  post-FTS regex pass produced matches; empty otherwise. The
	 *  frontend prefers offsets over the snippet when both are
	 *  present, splitting `content` into React nodes (no
	 *  `dangerouslySetInnerHTML`). Capped at
	 *  `MAX_OFFSETS_PER_BLOCK` per row to bound IPC payload size on
	 *  pathological patterns (e.g. `.` against a long block).
	 */
	match_offsets?: MatchOffset[],
};

/**
 *  Optional filter bundle for `search_blocks_inner`.
 *
 *  Phase 0 collapses the previous positional `parent_id` /
 *  `tag_ids` / `space_id` args into a single struct so the `tauri-specta`
 *  10-arg ceiling stays comfortable as follow-up plans append filter
 *  fields. Every field carries `#[serde(default)]` — a missing key on
 *  the wire deserialises to the field's `Default`, which preserves
 *  today's "no filter" behaviour. Follow-up plans append new fields the
 *  same way; they MUST NOT add positional args.
 *
 *  Future appendees (locked in by design section):
 *
 *  `include_page_globs`, `exclude_page_globs` (`Vec<String>`).
 *  `case_sensitive`, `whole_word`, `is_regex` (`bool`).
 *  `block_type_filter` (`Option<String>`).
 *  `state_filter`, `priority_filter`, `due_filter`,
 *    `scheduled_filter`, `property_filters`, `excluded_property_filters`.
 */
export type SearchFilter = {
	/**  Restrict results to direct children of this parent block. */
	parentId?: string | null,
	/**
	 *  Restrict results to blocks carrying every tag in this list
	 *  (`ALL` semantics — see `fts::search_fts`).
	 */
	tagIds?: string[],
	/**
	 *  Restrict to blocks whose owning page lives in this
	 *  space. Empty string is treated as "no match" by the SQL path
	 *  (returns an empty page), matching pre-bootstrap callers that
	 *  pass `''`.
	 */
	spaceId?: string | null,
	/**
	 *  Page-name glob include list. Each entry may use
	 *  SQLite `GLOB` syntax (`*`, `?`, `[...]`) and `{a,b}` brace
	 *  expansion. Bare tokens are wrapped with `*…*` for a
	 *  substring match. Resolved against `pages_cache.title` with
	 *  `LOWER(...)` for case-insensitive matching. See
	 *  `fts::glob_filter::prepare_globs` for the parsing pipeline.
	 */
	includePageGlobs?: string[],
	/**
	 *  Page-name glob exclude list. Same shape as
	 *  [`Self::include_page_globs`]; AND-joined into a `NOT IN (...)`
	 *  sub-select. A page matching both include and exclude is
	 *  excluded.
	 */
	excludePageGlobs?: string[],
	/**
	 *  Case-sensitive search toggle. When `true`, results are
	 *  narrowed by a post-FTS regex pass that asserts case-sensitive
	 *  match against `fts_blocks.stripped`. The FTS5 trigram tokenizer
	 *  is `case_sensitive 0`, so the candidate set is still
	 *  case-insensitive; this toggle forces the post-filter even when
	 *  the other toggles are off (documented cost). `#[serde(default)]`
	 *  Keeps the wire shape additive — pre- frontends omit the
	 *  field and observe today's behaviour unchanged.
	 */
	caseSensitive?: boolean,
	/**
	 *  Whole-word search toggle. ASCII-only via the regex
	 *  crate's `(?-u:\b)` predicate. CJK content does NOT match `\b`
	 *  (no ASCII word boundary inside CJK runs); v1 documents this and
	 *  a future plan revisits Unicode whole-word.
	 */
	wholeWord?: boolean,
	/**
	 *  Regex-mode search toggle. The query string is treated
	 *  as a Rust [`regex`] pattern verbatim; the FTS5 MATCH path is
	 *  **bypassed entirely** (FTS5 cannot accept a regex) and the
	 *  candidate set comes from a recency-ordered scan of
	 *  structurally-filtered blocks. Compile failures surface as
	 *  [`AppError::Validation`] with an `InvalidRegex:` prefix.
	 */
	isRegex?: boolean,
	/**
	 *  Restrict matches to a specific `blocks.block_type`
	 *  value (e.g. `"page"`). `None` (the default) preserves the
	 *  existing "no filter" behaviour. Empty string is rejected at the
	 *  SQL layer the same way as any other no-match equality. The
	 *  palette uses this to fire a separate page-only query in
	 *  parallel with the unrestricted blocks query so the page-group
	 *  rendering on the FE only needs to merge by `page_id`.
	 *  `#[serde(default)]` keeps the wire shape additive — pre-
	 *  frontends omit the field and observe today's behaviour
	 *  unchanged.
	 */
	blockTypeFilter?: string | null,
	/**
	 *  Restrict matches to blocks with `blocks.todo_state IN
	 *  (...)`. Each entry is matched verbatim — the column is a
	 *  free-form `TEXT` so custom states are allowed. The literal
	 *  keyword `none` (case-insensitive) selects `todo_state IS NULL`
	 *  (the `state:none` token); a custom state literally called
	 *  `"none"` is still matched correctly because the AST projects
	 *  `state:none` into a distinct sentinel (see the SQL composition).
	 */
	stateFilter?: string[],
	/**
	 *  `blocks.priority IN (...)`. Same `none` sentinel
	 *  behaviour as `state_filter`.
	 */
	priorityFilter?: string[],
	/**
	 *  Date predicate on `blocks.due_date`. `None` means
	 *  "no filter".
	 */
	dueFilter?: DateFilter | null,
	/**  Date predicate on `blocks.scheduled_date`. */
	scheduledFilter?: DateFilter | null,
	/**
	 *  AND-joined property filters. Each entry adds an
	 *  `EXISTS (SELECT 1 FROM block_properties …)` sub-select against
	 *  `value_text` (locked in by plan #4).
	 */
	propertyFilters?: SearchPropertyFilter[],
	/**
	 *  AND-joined property exclusions. Each entry adds a
	 *  `NOT EXISTS (...)` sub-select.
	 */
	excludedPropertyFilters?: SearchPropertyFilter[],
	/**
	 *  `blocks.todo_state IS NULL OR todo_state NOT IN
	 *  (...)`. Each entry is matched verbatim against the column. The
	 *  inversion intentionally includes NULL: a "blocks not in DONE"
	 *  query should return blocks with no state set at all, not
	 *  exclude them. The literal keyword `none` (case-insensitive)
	 *  flips to `todo_state IS NOT NULL` (the `not-state:none` token);
	 *  a custom state literally called `"none"` is treated as the
	 *  sentinel — documented in `docs/SEARCH.md`. Empty list = no
	 *  Filter (preserves pre- wire compat).
	 */
	excludedStateFilter?: string[],
	/**
	 *  `blocks.priority IS NULL OR priority NOT IN (...)`.
	 *  Same `none` sentinel behaviour as
	 *  [`Self::excluded_state_filter`].
	 */
	excludedPriorityFilter?: string[],
	/**
	 *  #1320-C — `last-edited:` time-window predicate. Resolved against
	 *  each block's last `op_log.created_at` (epoch-ms `MAX(...)`,
	 *  COALESCE'd to the epoch sentinel for blocks with no op-log row).
	 *  `None` (the default) preserves the existing "no filter" behaviour.
	 *  Compiled through [`crate::filters::primitive::SearchProjection`]
	 *  (`compile_last_edited`) and spliced into the dynamic FTS WHERE via
	 *  the [`crate::fts::filter_builder`] projection routing — see the
	 *  `add_last_edited_via_projection` splice. `#[serde(default)]` keeps
	 *  the wire shape additive: pre-#1320-C frontends omit the field and
	 *  observe today's behaviour unchanged.
	 */
	lastEdited?: LastEditedSpec | null,
};

/**
 *  Property predicate for [`SearchFilter::property_filters`] /
 *  [`SearchFilter::excluded_property_filters`].
 *
 *  Named separately from the (existing) `PropertyFilter` struct used by
 *  `filtered_blocks_query` — that one carries five typed value fields and
 *  a comparison operator; this one is the simpler `(key, value_text)`
 *  shape the inline `prop:key=value` token produces.
 *
 *  `value` is matched against `block_properties.value_text` (the
 *  most-common case for user-typed properties; locked in by the plan's
 *  "Locked-in decisions" #4). An empty `value` matches "block has this
 *  key at all" (`block_properties.value_text IS NOT NULL` is NOT
 *  required — only the key presence).
 */
export type SearchPropertyFilter = {
	/**  Property key — case-sensitive (locked in by plan #1). */
	key: string,
	/**
	 *  Property value — matched against `block_properties.value_text`.
	 *  Empty string treated as "key presence only".
	 */
	value: string,
};

/**
 *  Input bundle for the `set_property` Tauri command — collects all
 *  possible typed values into a single struct so the IPC handler stays
 *  Under specta's 10-positional-argument limit (added a 5th
 *  `value_bool` slot which would have made the flat signature exceed
 *  the cap). Exactly one field should be `Some` for non-reserved keys
 *  (the inner validator enforces this); reserved-key clears may pass
 *  all-None.
 */
export type SetPropertyArgs = {
	value_text?: string | null,
	value_num?: number | null,
	value_date?: string | null,
	value_ref?: string | null,
	/**  Native boolean property value (`true` / `false`). */
	value_bool?: boolean | null,
};

/**
 *  Snapshot of the most recent sync snapshot-fallback occurrence. Surfaced
 *  (cloned) through `StatusInfo::snapshot_fallback_last`.
 */
export type SnapshotFallbackLast = {
	/**
	 *  Monotonic ordinal of this occurrence within the process — equal to
	 *  [`count`] at the moment it was recorded. Lets an operator tell apart
	 *  "the count moved" from "the same stale `reason` is being re-read".
	 */
	occurrence: number,
	/**  Remote device / peer id whose `from_vv` could not be reached. */
	peer_id: string,
	/**  Per-space scope of the rejected update. */
	space_id: string,
	/**
	 *  Human-readable diagnostic from `classify_from_vv_reachability`
	 *  (carries the offending `peer={peer_id} counter>=…` detail).
	 */
	reason: string,
};

/**
 *  Snippet-rendering parameters threaded through to the FTS5 `snippet()`
 *  builtin. The SQL composition lives in `fts::search`.
 */
export type SnippetSpec = {
	maxTokens: number,
	leftMarker: string,
	rightMarker: string,
};

/**
 *  The closed set of columns an advanced query may sort on. Closed (rather
 *  than a free `String`) so a sort column can NEVER be a user-controlled
 *  string spliced into SQL.
 */
export type SortColumn =
/**
 *  Creation order. The block `id` is a ULID, whose lexical order is
 *  creation order, so `Created` maps to `b.id`.
 */
"created" |
/**
 *  Last-edited time: `MAX(op_log.created_at)` over the block, `COALESCE`d
 *  to the epoch sentinel for blocks with no op-log row (matching
 *  `PagesProjection::compile_last_edited`'s no-op-log rule).
 */
"lastEdited" |
/**  Sibling position (`b.position`). NULL positions sort last. */
"position" |
/**  `b.priority`. NULL priorities sort last. */
"priority" |
/**  Page title (`pages_cache.title`) of the block's owning page. */
"title";

/**  Sort direction. */
export type SortDir = "Asc" | "Desc";

/**
 *  One sort key: a source plus a direction. Keys are applied
 *  left-to-right; the engine always appends `b.id` as the final
 *  tiebreaker so the resulting keyset is total.
 */
export type SortKey = {
	/**  What to sort by. */
	source: SortSource,
	/**  Descending when `true` (default ascending). */
	desc?: boolean,
};

/**
 *  The thing a [`SortKey`] orders by.
 *
 *  Internally-tagged on `"type"`. `Column` sorts on a fixed block column.
 *  `Relevance` sorts on the full-text `bm25` rank and is ONLY valid when the
 *  request carries a `fulltext` term — the engine rejects it otherwise
 *  (there is no rank channel to sort on). `Aggregate` (group-by aggregate)
 *  and `VectorScore` (vector similarity) remain RESERVED for later
 *  fast-follows.
 */
export type SortSource =
/**
 *  Sort by a fixed, closed-set block column. The column name is NEVER a
 *  user-supplied string — it is a [`SortColumn`] enum the engine maps to
 *  a literal SQL column, so SQL injection through a sort key is
 *  impossible by construction.
 */
{ type: "Column"; name: SortColumn } |
/**
 *  Sort by full-text relevance (`fts.rank`, a `bm25` score — lower is
 *  better). Only valid when the request carries a `fulltext` term;
 *  otherwise the engine rejects it with a validation error.
 */
{ type: "Relevance" };

/**
 *  Newtype wrapper around a space ULID for type-safety + IPC bindings.
 *
 *  Mirrors [`crate::ulid::ActiveBlockId`] (the strict newtype):
 *  transparent serde + transparent sqlx + `specta::Type` so the wire / DB
 *  layers see a plain string while Rust call sites get the named type.
 *
 *  # Normalisation
 *
 *  Stored value is the canonical uppercase Crockford base32 representation —
 *  AGENTS.md invariant #8. Both `from_string`, `from_trusted`, and the
 *  `Deserialize` impl uppercase via `to_ascii_uppercase` so every path
 *  produces byte-identical output for non-ASCII inputs (e.g. "ß" stays "SS"
 *  is *not* what we want; `to_ascii_uppercase` is the only normaliser that
 *  keeps blake3 hash determinism).
 *
 *  # Wire format
 *
 *  `serde(transparent)` + `sqlx(transparent)` → JSON / SQLite see a bare
 *  string. Specta emits `export type SpaceId = string;`. The newtype is
 *  purely a Rust-side type-safety gate.
 */
export type SpaceId = string;

/**
 *  A space row returned by [`list_spaces_inner`] — the pieces the
 *  frontend needs to render the switcher (ULID + display name) plus
 *  The visual-identity surface (`accent_color`).
 *
 *  `accent_color` carries the free-form palette token (e.g.
 *  `accent-emerald`, `accent-blue`) stored under
 *  `block_properties(key='accent_color', value_text=…)`. `None` means
 *  the space has no explicit accent — the frontend falls back to the
 *  brand default. Joined via LEFT JOIN so an unset accent never hides
 *  the row.
 */
export type SpaceRow = {
	id: string,
	name: string,
	/**  Accent palette token, or `None` if unset. */
	accent_color: string | null,
};

/**
 *  The space scope a list / search query runs under.
 *
 *  `Global` — no `block_properties.space` filter is applied (pre-
 *  behaviour, plus journal / settings views that intentionally span all
 *  spaces). `Active(SpaceId)` — restrict results to blocks belonging to
 *  the given space.
 *
 *  # Wire format
 *
 *  Adjacently-tagged via `#[serde(tag = "kind", content = "space_id")]`:
 *
 *  - `SpaceScope::Global`              → `{"kind":"global"}`
 *  - `SpaceScope::Active(SpaceId(id))` → `{"kind":"active","space_id":"<ULID>"}`
 *
 *  Specta emits this as a TS discriminated union
 *  (`{ kind: "global" } | { kind: "active"; space_id: SpaceId }`).
 *
 *  # Deserialize validates the `Active` id shape (issue #1588)
 *
 *  The wire/SQL layers treat the inner `SpaceId` as a trusted-shape string —
 *  [`SpaceId::Deserialize`] only uppercase-normalises (mirroring `BlockId`),
 *  so without a guard a malformed `space_id` from the frontend / MCP / sync
 *  would bind a never-matching SQL filter param and silently return empty
 *  results. The hand-written `Deserialize` impl below deserialises through the
 *  same adjacently-tagged shape and then runs the lightweight ULID-shape check
 *  ([`SpaceScope::validate`]), so this IPC boundary rejects a malformed space
 *  id up front. `Global` and the seeded sentinel spaces are unaffected.
 */
export type SpaceScope = { kind: "global" } | { kind: "active"; space_id: SpaceId };

/**
 *  Snapshot of materializer + sync observability fields exposed to the
 *  frontend via `get_status`. Fields are added additively so existing
 *  specta-derived TS bindings keep compiling.
 */
export type StatusInfo = {
	foreground_queue_depth: number,
	background_queue_depth: number,
	total_ops_dispatched: number,
	total_background_dispatched: number,
	/**
	 *  Peak foreground queue depth observed in the current 5-minute
	 *  metrics-snapshot window. Resets every dump tick (see
	 *  `metrics_snapshot_task` in `coordinator.rs`); not an all-time peak.
	 */
	fg_high_water: number,
	/**
	 *  Peak background queue depth observed in the current 5-minute
	 *  metrics-snapshot window. Same windowed-reset semantics as
	 *  `fg_high_water`.
	 */
	bg_high_water: number,
	fg_errors: number,
	bg_errors: number,
	fg_panics: number,
	bg_panics: number,
	/**
	 *  Foreground `ApplyOp` / `BatchApplyOps` tasks dropped after the
	 *  100ms in-memory retry exhausted (C-2a). Surfaces
	 *  silent materializer divergence: a non-zero value means an
	 *  apply-op landed in the op log but never reached the
	 *  materialized `blocks` table on this run. Pair with the
	 *  `kind=ApplyOp` / `kind=BatchApplyOps` warn lines in the log
	 *  (which carry `seq` / `device_id` / `op_type`) for triage.
	 *  Each `BatchApplyOps` drop counts once regardless of batch size.
	 */
	fg_apply_dropped: number,
	/**
	 *  Subset of `fg_apply_dropped` whose retry row was
	 *  successfully persisted to `materializer_retry_queue`. The
	 *  boot-time / periodic sweeper re-enqueues these onto the
	 *  foreground queue so the apply-op is eventually retried. A
	 *  large gap between `fg_apply_dropped` and
	 *  `fg_apply_dropped_persisted` (after `BatchApplyOps` fan-out)
	 *  indicates the persistence write path is failing — pair with
	 *  `retry_queue_persist_errors` for triage.
	 */
	fg_apply_dropped_persisted: number,
	/**
	 *  Number of background tasks that were either persisted to the retry
	 *  queue or silently dropped after exhausting retries.
	 */
	bg_dropped: number,
	/**
	 *  Subset of `bg_dropped` attributable to global cache
	 *  rebuilds (`RebuildTagsCache`, `RebuildPagesCache`,
	 *  `RebuildAgendaCache`, `RebuildProjectedAgendaCache`,
	 *  `RebuildTagInheritanceCache`, `RebuildPageIds`,
	 *  `RebuildBlockTagRefsCache`). A non-zero value means at least
	 *  one global cache rebuild was shed or persisted on this run.
	 *  Worst-case staleness is bounded by the persistent-retry-queue
	 *  backoff cap (1h) because every dropped global task is also
	 *  recorded under the `'__GLOBAL__'` sentinel for sweeper-driven
	 *  re-enqueue.
	 */
	bg_dropped_global: number,
	/**
	 *  Running count of background tasks deduped in the batch drain (was
	 *  already tracked atomically; now surfaced).
	 */
	bg_deduped: number,
	/**
	 *  Number of times the foreground `enqueue_foreground` path awaited on
	 *  a full channel. Non-zero indicates backpressure.
	 */
	fg_full_waits: number,
	/**
	 *  Count of failed `record_failure` calls (i.e. retry
	 *  queue persistence writes that returned an error). Each
	 *  dropped task that fails persistence twice contributes `+2`
	 *  (first attempt + retry attempt). A non-zero value means the
	 *  retry-queue write path itself is degraded; pair with
	 *  `bg_dropped` and `fg_apply_dropped_persisted` to confirm
	 *  whether tasks are being lost to persist failures.
	 */
	retry_queue_persist_errors: number,
	/**
	 *  Issue #157 sub-item D — number of retry-queue rows the sweeper
	 *  has permanently given up on (hit `attempts >= MAX_ATTEMPTS` or
	 *  `created_at < now - GIVE_UP_AGE_DAYS`). A non-zero value means
	 *  at least one persisted task was permanently dropped on this
	 *  run; pair with the `give_up_reason=…` warn lines for triage.
	 */
	retry_queue_giveup_total: number,
	/**  RFC 3339 timestamp of the most recent successful batch, if any. */
	last_materialize_at: string | null,
	/**
	 *  Seconds elapsed since `last_materialize_at`. None when no batch has
	 *  completed yet.
	 */
	time_since_last_materialize_secs: number | null,
	/**
	 *  Row count of `op_log` at status-request time. `None` if the query
	 *  failed for any reason (the status call never fails because of it).
	 */
	total_ops_in_log: number | null,
	/**
	 *  `(peer_id, consecutive_failure_count)` pairs for every peer the
	 *  `SyncScheduler` has seen fail at least once. Empty when the
	 *  scheduler is not injected (tests, legacy callers).
	 */
	sync_peer_failure_counts: ([string, number])[],
	/**
	 *  Number of rows currently queued in `materializer_retry_queue` —
	 *  per-block tasks waiting for their next retry window.
	 */
	retry_queue_pending: number | null,
	/**
	 *  #1326 / #1057: process-global count of SQL-only fallbacks taken by
	 *  the `apply_*_via_loro` handlers (Loro engine uninitialised or block
	 *  space unresolved). Monotonic, never reset. **In production both
	 *  fallback arms are unreachable**, so a non-zero value signals an
	 *  unexpected engine-uninit or space-resolution miss that warrants
	 *  investigation — pair with the
	 *  `target=materializer::sql_only_fallback` debug lines (which carry
	 *  `op` + `reason`) for triage. Sourced from
	 *  [`super::handlers::sql_only_fallback::count`].
	 */
	sql_only_fallback_count: number,
	/**
	 *  #1319: process-global, cross-session count of sync snapshot-fallbacks
	 *  taken because a peer advertised a `from_vv` unreachable from our local
	 *  `oplog_vv()`. Monotonic, never reset. A steadily rising
	 *  value means sync keeps falling back to snapshot catch-up instead of
	 *  applying incremental updates — pair with `snapshot_fallback_last` (and
	 *  the `target=sync_protocol::snapshot_fallback` debug lines) to see the
	 *  offending peer / reason. Sourced from
	 *  [`crate::sync_protocol::snapshot_fallback_metrics::count`].
	 */
	snapshot_fallback_count: number,
	/**
	 *  #1319: the most recent sync snapshot-fallback occurrence (peer id,
	 *  space id, diagnostic reason, monotonic occurrence ordinal), or `None`
	 *  if none has happened in this process. Lets an operator correlate a
	 *  recurring fallback pattern without scraping per-session log lines.
	 *  Sourced from
	 *  [`crate::sync_protocol::snapshot_fallback_metrics::last`].
	 */
	snapshot_fallback_last: SnapshotFallbackLast | null,
};

/**
 *  Streaming progress payload carried over the sync channel.
 *
 *  Made this a tagged enum so a single channel per sync
 *  session carries both the orchestrator's state-transition stream
 *  (`Sync`) and the post-sync attachment-transfer stream (`Files`).
 *  Frontend consumers switch on `kind` and read the variant-specific
 *  fields.
 */
export type SyncProgressUpdate =
/**
 *  Op-sync state transitions (Tier 1). Mirrors the
 *  [`SyncEvent::Progress`] / [`SyncEvent::Complete`] /
 *  [`SyncEvent::Error`] envelope, with `state` carrying
 *  `"complete"` / `"error"` for the terminal cases.
 */
{ kind: "sync"; state: string; remote_device_id: string; ops_received: number; ops_sent: number } |
/**
 *  Per-frame attachment transfer progress (Tier 2). Emitted by
 *  `sync_files::run_file_transfer_*` between binary frames so the
 *  UI can render a real bytes-done bar instead of a spinner.
 */
{ kind: "files";
/**
 *  `"sending"` (we are pushing files to the peer),
 *  `"receiving"` (we are pulling files from the peer), or
 *  `"complete"` (both halves are done for this session).
 */
phase: string; remote_device_id: string;
/**  Files fully transferred so far in the current `phase`. */
files_done: number;
/**
 *  Total files the peer or we requested for this `phase`. May
 *  be 0 in the steady-state "nothing to transfer" case.
 */
files_total: number;
/**
 *  Bytes shipped/received so far in the current `phase`,
 *  including in-progress frames.
 */
bytes_done: number;
/**  Aggregate byte total advertised for the current `phase`. */
bytes_total: number };

/**  Response payload returned by [`start_sync`]. */
export type SyncSessionInfo = {
	state: string,
	local_device_id: string,
	remote_device_id: string,
	ops_received: number,
	ops_sent: number,
};

/**  Row from `tags_cache`, used by `list_tags_by_prefix`. */
export type TagCacheRow = {
	tag_id: string,
	name: string,
	usage_count: number,
	updated_at: string,
};

/**
 *  Boolean expression tree for tag queries.
 *
 *  # IPC wire format (#1472)
 *
 *  Adjacently-tagged via `#[serde(tag = "type", content = "value")]`, the
 *  same shape `SpaceScope` (`space.rs`) and `CursorValue` (`query/engine.rs`)
 *  use for tuple/newtype variants. Internal tagging (`#[serde(tag = "type")]`,
 *  as `FilterExpr` uses) cannot wrap the non-struct newtype payloads here
 *  (`Tag(String)` / `Not(Box<TagExpr>)`); adjacent tagging keeps the existing
 *  tuple-variant shape — so every in-tree constructor (`TagExpr::Tag(..)`,
 *  `TagExpr::And(vec![..])`, …) is unchanged — while still emitting a
 *  specta-expressible, self-describing TS discriminated union:
 *
 *  - `Tag("urgent")`      → `{ "type": "Tag",    "value": "urgent" }`
 *  - `Prefix("work/")`    → `{ "type": "Prefix", "value": "work/" }`
 *  - `And([a, b])`        → `{ "type": "And",    "value": [a, b] }`
 *  - `Or([a, b])`         → `{ "type": "Or",     "value": [a, b] }`
 *  - `Not(a)`             → `{ "type": "Not",    "value": a }`
 *
 *  The recursion bottoms out at the `Tag`/`Prefix` leaves, so the type is a
 *  self-referential discriminated union specta emits losslessly. Untrusted
 *  trees deserialised at the IPC boundary MUST be passed through
 *  [`TagExpr::validate_depth`] before resolution — `query_by_tag_expr`
 *  (`commands/tags.rs`) is the gate (see also `eval_tag_query`'s own
 *  `validate_depth` call for the And/Or/Not arms).
 */
export type TagExpr = { type: "Tag"; value: string } | { type: "Prefix"; value: string } | { type: "And"; value: TagExpr[] } | { type: "Or"; value: TagExpr[] } | { type: "Not"; value: TagExpr };

/**
 *  Tag predicate for [`filtered_blocks_query_inner`].
 *
 *  Mirrors the [`query_by_tags_inner`] arg shape. When `mode = "and"`
 *  every supplied tag (id or prefix) must match; `"or"` (default) is
 *  the union. The predicate is composed into ONE `AND EXISTS (…)`
 *  subquery in the parent SQL — the JS-side AND-intersection between
 *  property and tag sub-results disappears.
 */
export type TagFilterExpr = {
	/**  Explicit tag-block ULIDs. */
	tagIds?: string[],
	/**  Tag-name prefixes (resolved via `tags_cache.name LIKE ?`). */
	prefixes?: string[],
	/**
	 *  `"and"` for intersection across all tag matches, anything else
	 *  (default `"or"`) for union.
	 */
	mode?: string,
	/**
	 *  Whether to include inherited tags (`block_tag_inherited`) in
	 *  addition to direct (`block_tags`) and inline-ref
	 *  (`block_tag_refs`) associations. Defaults to `false`.
	 */
	includeInherited?: boolean,
};

export type TagResponse = {
	block_id: string,
	tag_id: string,
};

/**
 *  Payload describing the notification to fire for a due / scheduled task.
 *
 *  `title` is required and non-empty; `body` is optional (a notification
 *  with only a title is valid on every platform).  `block_id` is carried
 *  purely so the frontend / a future scheduler can correlate the
 *  notification with the originating block for dedupe — it is not surfaced
 *  to the OS.
 */
export type TaskNotification = {
	/**  The notification title (e.g. the task's text). Must be non-empty. */
	title: string,
	/**  Optional notification body (e.g. "Due 09:00" / "Scheduled in 10m"). */
	body?: string | null,
	/**
	 *  ULID of the originating block, for caller-side dedupe correlation.
	 *  Optional — a free-form notification need not reference a block.
	 */
	blockId?: string | null,
};

/**  Result of an undo or redo operation. */
export type UndoResult = {
	/**  The op that was reversed (the original op for undo, the undo-op for redo). */
	reversed_op: OpRef,
	/**
	 *  The op_type of the reversed op (e.g. `create_block`, `edit_block`, `set_property`).
	 *  Used by the frontend to show a descriptive toast ("Undid create", "Undid edit", etc.).
	 */
	reversed_op_type: string,
	/**  The newly appended reverse op. */
	new_op_ref: OpRef,
	/**  The op_type of the newly appended op. */
	new_op_type: string,
	/**  Whether this was a redo (true) or undo (false). */
	is_redo: boolean,
};

/**
 *  A single referenced sibling file carried over IPC for an attachment-aware
 *  import (#1925).
 *
 *  The frontend (PR 2) pre-scans the picked Logseq/Obsidian vault, collects ONLY
 *  the files actually referenced by the markdown being imported (image embeds,
 *  `assets/...` refs, etc.), reads each into a browser `ArrayBuffer`, and sends
 *  the `{ path, bytes }` pairs alongside the markdown `content`. The backend
 *  matches each in-content attachment ref against this list, ingests the matched
 *  bytes as an attachment (deduping by `content_hash`), and rewrites the ref to
 *  the canonical `attachment:<id>` form.
 *
 *  `path` is the file's path RELATIVE to the vault root (the browser
 *  `webkitRelativePath` minus the top folder, or whatever the FE chooses), using
 *  `/` separators — e.g. `assets/diagram.png` or `images/screenshots/a.png`.
 *  It is matched against an in-content ref first by relative-path equality, then
 *  by basename (see `match_vault_file`).
 *
 *  This is an IPC **input**, so it needs `Deserialize` (unlike the
 *  backend→frontend [`ImportProgressUpdate`], which is `Serialize`-only).
 */
export type VaultFile = {
	/**  Vault-root-relative path, `/`-separated (e.g. `assets/img.png`). */
	path: string,
	/**  Raw file bytes. */
	bytes: number[],
};

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}
